const channel = $input.first().json.items[0];
const accountId = $('Get YouTube Accounts').item.json.account_id;

return {
  account_id: accountId,
  username: channel.snippet.title,
  display_name: channel.snippet.customUrl || channel.snippet.title,
  followers_count: parseInt(channel.statistics.subscriberCount),
  metadata: {
    description: channel.snippet.description,
    thumbnail: channel.snippet.thumbnails.high.url,
    total_videos: parseInt(channel.statistics.videoCount),
    total_views: parseInt(channel.statistics.viewCount),
    uploads_playlist: channel.contentDetails.relatedPlaylists.uploads
  }
};

// Get video stats from the API response
const videoData = $input.first().json.items[0];
// Get account ID from the original query
const accountId = $('Get YouTube Accounts').item.json.account_id;

// Parse duration (PT15M30S -> 930 seconds)
const parseDuration = (duration) => {
  const match = duration.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  if (!match) return 0;
  const hours = parseInt(match[1] || 0);
  const minutes = parseInt(match[2] || 0);
  const seconds = parseInt(match[3] || 0);
  return hours * 3600 + minutes * 60 + seconds;
};

// Extract title and description
const title = videoData.snippet.title;
const description = videoData.snippet.description || '';
const lines = description.split('\n').filter(line => line.trim());
const hook = title;
const idea = lines.slice(0, 3).join(' ').substring(0, 500);

// Determine content type based on duration
const duration = parseDuration(videoData.contentDetails.duration);
let contentType = 'video';
if (duration < 60) contentType = 'short';

return {
  // Content data
  content_id: videoData.id,
  account_id: accountId,
  platform: 'youtube',
  content_type: contentType,
  title: title,
  hook: hook,
  idea: idea,
  url: `https://www.youtube.com/watch?v=${videoData.id}`,
  posted_at: videoData.snippet.publishedAt,
  duration_sec: duration,
  metadata: {
    thumbnail: videoData.snippet.thumbnails.high.url,
    tags: videoData.snippet.tags || [],
    category_id: videoData.snippet.categoryId
  },

  // Metrics data
  date: new Date().toISOString().split('T')[0],
  views: parseInt(videoData.statistics.viewCount || 0),
  likes: parseInt(videoData.statistics.likeCount || 0),
  comments: parseInt(videoData.statistics.commentCount || 0),
  shares: 0, // YouTube API doesn't provide shares directly
  saves: 0
};
